+// Animated counter — REVELATION beat "Counter reveal" pattern
+// easeOutExpo: fast start, slow finish. Duration ~1.2s via RAF.
+function animateCounter(elementId, targetValue, duration = 1200) {
+  const el = document.getElementById(elementId);
+  if (!el) return;
+  const start = performance.now();
+  const startVal = 0;
+  function tick(now) {
+    const t = Math.min(1, (now - start) / duration);
+    // easeOutExpo: 1 - 2^(-10t)
+    const eased = t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
+    const current = Math.round(startVal + (targetValue - startVal) * eased);
+    el.textContent = current.toLocaleString();
+    if (t < 1) requestAnimationFrame(tick);
+  }
+  requestAnimationFrame(tick);
+}
