+// Keyboard navigation for outcome cards (arrow keys)
+document.addEventListener('keydown', (e) => {
+  const cards = document.querySelectorAll('.outcome-card');
+  if (!cards.length) return;
+  const focused = document.activeElement;
+  if (!focused || !focused.classList.contains('outcome-card')) return;
+  const ids = ['ok', 'err', 'cancelled', 'panicked'];
+  const currentIdx = ids.indexOf(focused.dataset.id);
+  if (currentIdx < 0) return;
+  let newIdx = -1;
+  if (e.key === 'ArrowRight' || e.key === 'ArrowDown') newIdx = Math.min(currentIdx + 1, ids.length - 1);
+  else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') newIdx = Math.max(currentIdx - 1, 0);
+  if (newIdx >= 0 && newIdx !== currentIdx) {
+    e.preventDefault();
+    const newCard = document.getElementById('oc-' + ids[newIdx]);
+    if (newCard) { newCard.focus(); selectOutcome(ids[newIdx]); }
+  }
+});
